import React, { useState, useEffect } from "react";
import StudentCard from "./components/StudentCard";

function App() {
  const [students, setStudents] = useState([]);

  /* ---------------- FETCH USERS ---------------- */
  useEffect(() => {
    fetch("http://localhost:3000/users")
      .then(res => res.json())
      .then(data => setStudents(data));
  }, []);

  /* ---------------- ADD USER ---------------- */
  const handleAdd = async () => {
    const res = await fetch("http://localhost:3000/users", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        name: "New User",
        email: "new@gmail.com"
      })
    });

    const data = await res.json();
    setStudents([...students, data]);
  };

  /* ---------------- UPDATE USER ---------------- */
  const handleUpdate = async (id) => {
    await fetch(`http://localhost:3000/users/${id}`, {
      method: "PUT",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        name: "Updated Name"
      })
    });

    alert("Updated!");
  };

  /* ---------------- LOGIN ---------------- */
  const handleLogin = async () => {
    const res = await fetch("http://localhost:3000/login", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        email: "test@gmail.com"
      })
    });

    const data = await res.json();
    localStorage.setItem("token", data.token);

    alert("Login success");
  };

  /* ---------------- PROFILE ---------------- */
  const getProfile = async () => {
    const token = localStorage.getItem("token");

    const res = await fetch("http://localhost:3000/profile", {
      headers: {
        Authorization: `Bearer ${token}`
      }
    });

    const data = await res.json();
    console.log(data);

    alert("Check console");
  };

  return (
    <div style={mainContainer}>
      <h1 style={title}>🎓 Student Dashboard</h1>

      {/* Profile Card */}
      <div style={profileCard}>
        <h2>Subaranjani</h2>
        <p>🚀 Full Stack Developer</p>
        <span style={status}>● Active</span>
      </div>

      {/* Buttons */}
      <div style={buttonGroup}>
        <button style={btn} onClick={handleAdd}>➕ Add User</button>
        <button style={btn} onClick={handleLogin}>🔐 Login</button>
        <button style={btn} onClick={getProfile}>👤 Profile</button>
      </div>

      <h2 style={{ marginTop: "40px" }}>👥 Users</h2>

      {/* User Cards */}
      <div style={grid}>
        {students.map((user) => (
          <div
            key={user._id}
            style={userCard}
            onMouseOver={(e) => (e.currentTarget.style.transform = "scale(1.05)")}
            onMouseOut={(e) => (e.currentTarget.style.transform = "scale(1)")}
          >
            <h3>{user.name}</h3>
            <p>{user.email}</p>

            <button
              style={updateBtn}
              onClick={() => handleUpdate(user._id)}
            >
              ✏️ Update
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

/* ---------------- STYLES ---------------- */

const mainContainer = {
  minHeight: "100vh",
  background: "linear-gradient(135deg, #667eea, #764ba2)",
  padding: "30px",
  textAlign: "center",
  fontFamily: "Poppins, sans-serif",
  color: "white"
};

const title = {
  fontSize: "32px",
  marginBottom: "20px"
};

const profileCard = {
  background: "rgba(255,255,255,0.15)",
  backdropFilter: "blur(10px)",
  padding: "20px",
  borderRadius: "15px",
  width: "300px",
  margin: "auto",
  boxShadow: "0 8px 20px rgba(0,0,0,0.2)"
};

const status = {
  color: "#2ecc71",
  fontWeight: "bold"
};

const buttonGroup = {
  marginTop: "25px"
};

const btn = {
  margin: "10px",
  padding: "12px 20px",
  borderRadius: "10px",
  border: "none",
  background: "#ffffff",
  color: "#333",
  fontWeight: "bold",
  cursor: "pointer"
};

const grid = {
  display: "grid",
  gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))",
  gap: "20px",
  marginTop: "30px"
};

const userCard = {
  background: "white",
  color: "black",
  padding: "20px",
  borderRadius: "15px",
  boxShadow: "0 5px 15px rgba(0,0,0,0.2)",
  transition: "0.2s"
};

const updateBtn = {
  marginTop: "10px",
  padding: "8px 15px",
  border: "none",
  borderRadius: "8px",
  background: "#667eea",
  color: "white",
  cursor: "pointer"
};

export default App;
